def maxAverageOfPath(cost):
    N = len(cost)
    if N == 0:
        return 0.0
    dp = [0] * N
    dp[0] = cost[0][0]
    for j in range(1, N):
        dp[j] = dp[j-1] + cost[0][j]
    for i in range(1, N):
        dp[0] += cost[i][0]
        for j in range(1, N):
            dp[j] = cost[i][j] + max(dp[j], dp[j-1])
