def rgb_to_hsv(r, g, b):
    """Converts RGB color to HSV color.
    """
    r = r / 255.0
    g = g / 255.0
    b = b / 255.0

    cmax = max(r, g, b)
    cmin = min(r, g, b)
    delta = cmax - cmin

    if delta == 0:
        h = 0
        s = 0
    elif cmax == r:
        h = 60 * ( (g - b) / delta )
        s = delta / cmax
    elif cmax == g:
        h = 60 * ( (b - r) / delta ) + 120
        s = delta / cmax
    elif cmax == b:
        h = 60 * ( (r - g) / delta ) + 240
        s = delta / cmax
    else:
        return None

    if s == 0:
        h = 0
    elif h < 0:
        h += 360

    return (h, s, 1.0)
