            if (i >> j) & 1:
                subset.append(a[j])

        if not subset:
            continue

        is_divisible = True
        for k in range(len(subset)):
            for l in range(k + 1, len(subset)):
                if subset[k] % subset[l] != 0:
                    is_divisible = False
                    break
            if not is_divisible:
